from __future__ import annotations

from pathlib import Path
from shutil import copy2
from typing import Iterable


def prepare_example_outputs_for_docs(
    example_file: str,
    output_dir_name: str,
    table_suffix: str = "_optimal_parameters.txt",
    image_patterns: Iterable[str] = ("*.png",),
) -> dict[str, Path]:
    """
    Copy example output files into the matching Sphinx-Gallery output directory.

    This helper is intended for documentation examples. It copies all matching
    image files and the optimal-parameters table into the corresponding
    ``docs/source/auto_examples/<gallery_subdir>/<output_dir_name>/`` folder,
    so they can be referenced from the example docstring using relative paths.

    Parameters
    ----------
    example_file
        Usually ``__file__`` from the example script.
    output_dir_name
        Name of the local output directory generated by the example, e.g.
        ``"output_one_pulse"``.
    table_suffix
        Suffix used to identify the optimal-parameters text file.
    image_patterns
        File patterns for images to copy.

    Returns
    -------
    dict[str, Path]
        Dictionary containing:
        - ``"destination_dir"``: destination directory in docs
        - ``"table_file"``: copied table file, if found
    """
    example_path = Path(example_file).resolve()

    # For example:
    # .../tracts/example/3pops_sexbiased/ASW/ASW_one_pulse.py
    gallery_subdir = example_path.parent.name
    project_root = example_path.parents[3]

    src_out = example_path.parent / output_dir_name
    dst_out = (
        project_root
        / "docs"
        / "source"
        / "auto_examples"
        / gallery_subdir
        / output_dir_name
    )

    if not src_out.exists():
        raise FileNotFoundError(f"Source output directory does not exist: {src_out}")

    dst_out.mkdir(parents=True, exist_ok=True)

    # Copy image files
    for pattern in image_patterns:
        for f in src_out.glob(pattern):
            if f.is_file():
                copy2(f, dst_out / f.name)

    result: dict[str, Path] = {"destination_dir": dst_out}

    # Copy the optimal-parameters table file
    table_candidates = sorted(src_out.glob(f"*{table_suffix}"))
    if table_candidates:
        table_file = table_candidates[0]
        copied_table = dst_out / table_file.name
        copy2(table_file, copied_table)
        result["table_file"] = copied_table

    return result